import {
  ApiOutlined,
  CheckCircleOutlined,
  SafetyCertificateOutlined,
  ThunderboltOutlined,
} from '@ant-design/icons';
import { Alert, Col, Flex, Row, Segmented, Typography } from 'antd';
import { useState } from 'react';

import { getDashboardSummary } from '../api/dashboard';
import { Page } from '../components/layout/Page';
import { MetricCard } from '../components/dashboard/MetricCard';
import { QualityTrends } from '../components/dashboard/QualityTrends';
import { RecentRuns } from '../components/dashboard/RecentRuns';
import { SuitePerformance } from '../components/dashboard/SuitePerformance';
import { useAsyncData } from '../hooks/useAsyncData';

/**
 * Enhanced Monitoring Dashboard (`/dashboard`, ADR 0022) — the post-login
 * landing. Phase 2.2 ships the KPI row + range selector; the Quality Trends
 * chart, Suite Performance bars, and Recent Runs table land in 2.3–2.5.
 *
 * Every KPI is backed by the summary endpoint — the prototype's "Total
 * Anomalies" and "Avg. Time to Resolution" tiles are intentionally omitted
 * (no query backs them yet; KPI honesty, ADR 0022 / 0018).
 */

/** Range option label → trailing window in days for the summary query. */
const RANGES = [
  { label: 'Last 24h', days: 1 },
  { label: '7d', days: 7 },
  { label: '30d', days: 30 },
] as const;
type RangeLabel = (typeof RANGES)[number]['label'];

function pct(value: number | null): string | null {
  return value === null ? null : `${value}`;
}

export function Dashboard() {
  const [range, setRange] = useState<RangeLabel>('7d');
  const days = RANGES.find((r) => r.label === range)?.days ?? 7;
  // Re-fetch when the range changes: bump the fetcher via `reload` after the
  // range state updates (both batch into one render → the effect re-runs with
  // the new window).
  const { state, reload } = useAsyncData(() => getDashboardSummary(days));

  const onRangeChange = (value: RangeLabel) => {
    setRange(value);
    reload();
  };

  const loading = state.status === 'loading';
  const summary = state.status === 'ok' ? state.data : null;
  const kpis = summary?.kpis ?? null;

  return (
    <Page gap={20}>
      <Flex justify="space-between" align="center" gap={12} wrap>
        <div>
          <Typography.Title level={3} style={{ margin: 0 }}>
            Monitoring Dashboard
          </Typography.Title>
          <Typography.Text type="secondary">Your workspace data-quality health.</Typography.Text>
        </div>
        <Segmented<RangeLabel>
          value={range}
          onChange={onRangeChange}
          options={RANGES.map((r) => r.label)}
        />
      </Flex>

      {state.status === 'error' && (
        <Alert type="error" showIcon message="Failed to load dashboard" description={state.error} />
      )}

      <Row gutter={[16, 16]}>
        <Col xs={24} sm={12} xl={6}>
          <MetricCard
            label="Data Integrity Score"
            value={pct(kpis?.health_score ?? null)}
            unit="%"
            icon={<SafetyCertificateOutlined />}
            progress={kpis?.health_score ?? null}
            loading={loading}
          />
        </Col>
        <Col xs={24} sm={12} xl={6}>
          <MetricCard
            label="Pass Rate"
            value={pct(kpis?.pass_rate ?? null)}
            unit="%"
            icon={<CheckCircleOutlined />}
            progress={kpis?.pass_rate ?? null}
            loading={loading}
          />
        </Col>
        <Col xs={24} sm={12} xl={6}>
          <MetricCard
            label="Total Runs"
            value={kpis ? kpis.total_runs : null}
            icon={<ThunderboltOutlined />}
            footnote={`Last ${days === 1 ? '24h' : `${days} days`}`}
            loading={loading}
          />
        </Col>
        <Col xs={24} sm={12} xl={6}>
          <MetricCard
            label="Active Connections"
            value={kpis ? kpis.active_connections : null}
            unit="operational"
            icon={<ApiOutlined />}
            loading={loading}
          />
        </Col>
      </Row>

      <Row gutter={[16, 16]}>
        <Col xs={24} xl={15}>
          <QualityTrends trend={summary?.trend ?? []} />
        </Col>
        <Col xs={24} xl={9}>
          <SuitePerformance suites={summary?.suite_performance ?? []} />
        </Col>
      </Row>

      <RecentRuns />
    </Page>
  );
}

import type { ThemeConfig } from 'antd';

/**
 * App-wide Ant Design theme. Kept in one module so the brand palette and the
 * shell (App.tsx) read from the same tokens rather than hard-coding hexes.
 *
 * Design intent: move off the stock antd "navy-header admin template" look.
 * An indigo primary + a soft gray layout canvas (`colorBgLayout`) give the
 * white surfaces (header, sider, cards) depth and definition — so the page no
 * longer reads as a flat sea of white, and the empty space frames content
 * instead of just being blank.
 */

export const BRAND = {
  /** Indigo-600 — the primary accent (buttons, active nav, links). */
  primary: '#4f46e5',
  /** Indigo-200 — the logo's light lobe + the watermark tint. */
  primarySoft: '#c7d2fe',
  /** Pale indigo — the "selected" row/nav background (one tint everywhere). */
  selectedBg: '#eef0fe',
  /** The soft canvas behind white surfaces. */
  canvas: '#f4f5f7',
  /** Hairline border for header / sider / cards. */
  border: '#e6e8eb',
  /** Primary text. */
  ink: '#1f2430',
} as const;

/** Shared shell metrics so App.tsx and the theme agree. */
export const SHELL = {
  headerHeight: 56,
  siderWidth: 220,
} as const;

export const appTheme: ThemeConfig = {
  token: {
    colorPrimary: BRAND.primary,
    colorInfo: BRAND.primary,
    colorLink: BRAND.primary,
    colorTextHeading: BRAND.ink,
    colorBgLayout: BRAND.canvas,
    borderRadius: 8,
    fontFamily:
      "'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Helvetica, Arial, sans-serif",
    fontSize: 14,
  },
  components: {
    Layout: {
      headerBg: '#ffffff',
      headerHeight: SHELL.headerHeight,
      headerPadding: '0 24px',
      siderBg: '#ffffff',
      bodyBg: BRAND.canvas,
    },
    Menu: {
      // Rounded, inset nav items read as a modern sidebar rather than full-bleed rows.
      itemBorderRadius: 8,
      itemMarginInline: 8,
      itemHeight: 38,
      itemSelectedBg: BRAND.selectedBg,
      itemSelectedColor: BRAND.primary,
    },
    Card: {
      borderRadiusLG: 12,
    },
    Table: {
      headerBg: '#fafbfc',
    },
  },
};

