() => {
  const bodyFont = getComputedStyle(document.body).fontFamily;
  const interLoaded = document.fonts.check("16px 'Inter'");
  const monoLoaded = document.fonts.check("16px 'JetBrains Mono'");
  const rootPrimary = getComputedStyle(document.documentElement).getPropertyValue('--dq-primary').trim();
  const ease = getComputedStyle(document.documentElement).getPropertyValue('--dq-ease').trim();
  return { bodyFont, interLoaded, monoLoaded, rootPrimary, ease, loadedFonts: [...document.fonts].map(f => f.family + ' ' + f.weight + ' ' + f.status).slice(0, 8) };
}

() => {
  const btn = document.querySelector('button');
  if (btn) btn.focus();
  const s = btn ? getComputedStyle(btn) : null;
  return { focusedTag: document.activeElement?.tagName, outline: s ? s.outlineColor + ' ' + s.outlineWidth + ' ' + s.outlineStyle : null };
}

